"""

title: Add Web Sources to Knowledge
author: @G30
author_url: https://openwebui.com/u/g30
funding_url: https://github.com/open-webui
version: 0.1.3
license: MIT
required_open_webui_version: 0.8.12
icon_url: data:image/svg+xml;base64,
"""

import asyncio
import uuid
import re
import inspect
import json as _json

from pydantic import BaseModel, Field
from typing import Optional


class Action:
    """
    Action function that adds web search result URLs to a Knowledge base.

    When a message contains sources from web search, this action button allows
    users to save those sources directly to their Knowledge base.

    MODIFIED (v0.1.3): Replaced both URL selection and KB selection with checkbox UI; added ability to create new knowledge collections inline.
    featuring a "Select All" button for easier source selection.
    """

    class Valves(BaseModel):
        """Admin-level configuration options (system-wide defaults)."""

        priority: int = Field(
            default=0,
            description="Priority level for button sorting in the UI (lower numbers appear first).",
        )

        max_urls_per_action: int = Field(
            default=10,
            description="Maximum number of URLs to process in a single action (prevents abuse)",
        )
        enable_duplicate_check: bool = Field(
            default=True,
            description="Check if URL already exists in the knowledge base before adding",
        )
        default_knowledge_base: str = Field(
            default="", description="System-wide default Knowledge Base name or ID"
        )
        skip_confirmation: bool = Field(
            default=False, description="System-wide default: skip confirmation dialog"
        )
        file_name_prefix: str = Field(
            default="",
            description="System-wide default prefix for file names (e.g., 'web_')",
        )

    class UserValves(BaseModel):
        """User-level configuration options."""

        default_knowledge_base: str = Field(
            default="",
            description="Default Knowledge Base name or ID. If set, skips the selection dialog.",
        )
        skip_confirmation: bool = Field(
            default=False,
            description="Skip confirmation dialog and use default KB (requires default_knowledge_base to be set)",
        )
        file_name_prefix: str = Field(
            default="",
            description="Prefix to add to file names (e.g., 'web_' or 'source_')",
        )

    def __init__(self):
        self.valves = self.Valves()

    async def action(
        self,
        body: dict,
        __user__: dict = None,
        __event_emitter__=None,
        __event_call__=None,
        __request__=None,
    ) -> Optional[dict]:
        """
        Main action handler that processes the message sources and adds them to Knowledge.
        """
        # Get user valves (with fallback to admin valve defaults)
        user_valves = __user__.get("valves", None) if __user__ else None
        if user_valves and isinstance(user_valves, self.UserValves):
            uv = user_valves
        elif user_valves and isinstance(user_valves, dict):
            uv = self.UserValves(**user_valves)
        else:
            uv = self.UserValves()

        # Merge settings
        effective_default_kb = (
            uv.default_knowledge_base
            if uv.default_knowledge_base
            else self.valves.default_knowledge_base
        )
        effective_skip_confirm = uv.skip_confirmation or self.valves.skip_confirmation
        effective_prefix = (
            uv.file_name_prefix if uv.file_name_prefix else self.valves.file_name_prefix
        )

        # Extract messages and find sources
        messages = body.get("messages", [])
        urls = []

        for message in messages:
            sources = message.get("sources", [])
            if sources:
                for source in sources:
                    # Structure 1: source has 'source' object with url/name
                    source_obj = source.get("source", {})
                    if source_obj:
                        url = source_obj.get("url") or source_obj.get("name", "")
                        if url and (
                            url.startswith("http://") or url.startswith("https://")
                        ):
                            if not any(u["url"] == url for u in urls):
                                urls.append(
                                    {"url": url, "name": source_obj.get("name", url)}
                                )

                    # Structure 2: metadata array with source URLs
                    metadata_list = source.get("metadata", [])
                    for meta in metadata_list if metadata_list else []:
                        meta_source = meta.get("source", "")
                        if meta_source and (
                            meta_source.startswith("http://")
                            or meta_source.startswith("https://")
                        ):
                            if not any(u["url"] == meta_source for u in urls):
                                urls.append({"url": meta_source, "name": meta_source})

        print(
            f"[Add to Knowledge] Found {len(urls)} URLs from {len(messages)} messages"
        )

        if not urls:
            await __event_emitter__(
                {
                    "type": "notification",
                    "data": {
                        "type": "warning",
                        "content": "No web URLs found in message sources. This action works with web search results.",
                    },
                }
            )
            return None

        # Apply max URLs limit from admin valves
        if len(urls) > self.valves.max_urls_per_action:
            urls = urls[: self.valves.max_urls_per_action]
            await __event_emitter__(
                {
                    "type": "notification",
                    "data": {
                        "type": "info",
                        "content": f"Limited to {self.valves.max_urls_per_action} URLs (admin setting)",
                    },
                }
            )

        # Get available knowledge bases
        await __event_emitter__(
            {"type": "status", "data": {"description": "Loading knowledge bases..."}}
        )

        try:
            from open_webui.models.knowledge import Knowledges

            knowledge_bases = await Knowledges.get_knowledge_bases_by_user_id(
                user_id=__user__["id"], permission="write"
            )

            if not knowledge_bases:
                knowledge_bases = await Knowledges.get_knowledge_bases(
                    user_id=__user__["id"]
                )

            if not knowledge_bases:
                await __event_emitter__(
                    {"type": "status", "data": {"description": "", "done": True}}
                )
                await __event_emitter__(
                    {
                        "type": "notification",
                        "data": {
                            "type": "error",
                            "content": "No knowledge bases found. Please create one first.",
                        },
                    }
                )
                return None

            selected_kb = None

            # Check if user/admin has a default KB set
            if effective_default_kb:
                default_kb_lower = effective_default_kb.lower().strip()
                for kb in knowledge_bases:
                    if (
                        kb.id == effective_default_kb
                        or kb.name.lower() == default_kb_lower
                    ):
                        selected_kb = kb
                        break

                if not selected_kb:
                    await __event_emitter__(
                        {
                            "type": "notification",
                            "data": {
                                "type": "warning",
                                "content": f"Default KB '{effective_default_kb}' not found. Please select manually.",
                            },
                        }
                    )

            # If no default KB or skip_confirmation is False, ask user
            if not selected_kb or not effective_skip_confirm:
                # ────────────────────────────────────────────────
                # Step 1: URL Selection Dialog (CHECKBOX UI)
                # Replaces the old text-based input with a rich
                # checkbox modal featuring "Select All" button.
                # ────────────────────────────────────────────────
                urls_json = _json.dumps(
                    [{"url": u["url"], "name": u["name"]} for u in urls]
                )

                url_response = await __event_call__(
                    {
                        "type": "execute",
                        "data": {
                            "code": f"""
                                return new Promise((resolve) => {{
                                    const urls = {urls_json};
                                    const overlay = document.createElement('div');
                                    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.5);display:flex;align-items:center;justify-content:center;z-index:9999;font-family:system-ui,-apple-system,sans-serif';

                                    let itemsHtml = '';
                                    urls.forEach((u, i) => {{
                                        const displayUrl = u.url.length > 70 ? u.url.substring(0, 70) + '...' : u.url;
                                        itemsHtml += `
                                            <label style="display:flex;align-items:flex-start;padding:8px 10px;margin:2px 0;border-radius:6px;cursor:pointer;transition:background 0.15s"
                                                   onmouseover="this.style.background='#f0f0f0'" 
                                                   onmouseout="this.style.background='transparent'">
                                                <input type="checkbox" class="owui-url-cb" value="${{i}}" checked 
                                                       style="margin-top:2px;margin-right:10px;min-width:16px;width:16px;height:16px;cursor:pointer"/>
                                                <div>
                                                    <div style="font-weight:500;font-size:13px;color:#1a1a1a">${{i+1}}. ${{u.name || displayUrl}}</div>
                                                    <div style="font-size:11px;color:#666;word-break:break-all">${{displayUrl}}</div>
                                                </div>
                                            </label>
                                        `;
                                    }});

                                    overlay.innerHTML = `
                                        <div style="background:#fff;border-radius:12px;box-shadow:0 20px 60px rgba(0,0,0,0.3);max-width:620px;width:90vw;max-height:80vh;display:flex;flex-direction:column">
                                            <div style="padding:16px 20px;border-bottom:1px solid #e5e5e5;display:flex;align-items:center;justify-content:space-between">
                                                <h3 style="margin:0;font-size:16px;font-weight:600">Select Sources to Add</h3>
                                                <span style="font-size:13px;color:#888">${{urls.length}} source(s) found</span>
                                            </div>
                                            <div style="padding:8px 12px;border-bottom:1px solid #e5e5e5;display:flex;gap:8px">
                                                <button id="owui-select-all" style="padding:6px 14px;border:1px solid #d0d0d0;border-radius:6px;background:#fff;cursor:pointer;font-size:12px;font-weight:500;color:#333;transition:all 0.15s"
                                                        onmouseover="this.style.background='#f5f5f5'" 
                                                        onmouseout="this.style.background='#fff'">
                                                    Select All
                                                </button>
                                                <button id="owui-deselect-all" style="padding:6px 14px;border:1px solid #d0d0d0;border-radius:6px;background:#fff;cursor:pointer;font-size:12px;font-weight:500;color:#333;transition:all 0.15s"
                                                        onmouseover="this.style.background='#f5f5f5'" 
                                                        onmouseout="this.style.background='#fff'">
                                                    Deselect All
                                                </button>
                                            </div>
                                            <div style="overflow-y:auto;padding:4px 12px;flex:1;min-height:0">
                                                ${{itemsHtml}}
                                            </div>
                                            <div style="padding:12px 20px;border-top:1px solid #e5e5e5;display:flex;gap:8px;justify-content:flex-end">
                                                <button id="owui-cancel" style="padding:8px 20px;border:1px solid #d0d0d0;border-radius:8px;background:#fff;cursor:pointer;font-size:13px;font-weight:500;color:#555;transition:all 0.15s"
                                                        onmouseover="this.style.background='#f5f5f5'" 
                                                        onmouseout="this.style.background='#fff'">
                                                    Cancel
                                                </button>
                                                <button id="owui-submit" style="padding:8px 24px;border:none;border-radius:8px;background:#1a1a1a;cursor:pointer;font-size:13px;font-weight:600;color:#fff;transition:all 0.15s"
                                                        onmouseover="this.style.background='#333'" 
                                                        onmouseout="this.style.background='#1a1a1a'">
                                                    Add Selected
                                                </button>
                                            </div>
                                        </div>
                                    `;

                                    document.body.appendChild(overlay);

                                    const checkboxes = overlay.querySelectorAll('.owui-url-cb');

                                    const updateSelectAllBtn = () => {{
                                        const allChecked = Array.from(checkboxes).every(cb => cb.checked);
                                        const noneChecked = Array.from(checkboxes).every(cb => !cb.checked);
                                        const btn = document.getElementById('owui-select-all');
                                        const deselectBtn = document.getElementById('owui-deselect-all');
                                        if (allChecked) {{
                                            btn.textContent = 'All Selected';
                                            btn.style.background = '#e8f4e8';
                                            btn.style.borderColor = '#a0d0a0';
                                            deselectBtn.style.display = 'inline-block';
                                        }} else if (noneChecked) {{
                                            btn.textContent = 'Select All';
                                            btn.style.background = '#fff';
                                            btn.style.borderColor = '#d0d0d0';
                                            deselectBtn.style.display = 'none';
                                        }} else {{
                                            btn.textContent = 'Select All';
                                            btn.style.background = '#fff';
                                            btn.style.borderColor = '#d0d0d0';
                                            deselectBtn.style.display = 'inline-block';
                                        }}
                                    }};

                                    document.getElementById('owui-select-all').onclick = () => {{
                                        const allChecked = Array.from(checkboxes).every(cb => cb.checked);
                                        checkboxes.forEach(cb => cb.checked = !allChecked);
                                        updateSelectAllBtn();
                                    }};

                                    document.getElementById('owui-deselect-all').onclick = () => {{
                                        checkboxes.forEach(cb => cb.checked = false);
                                        updateSelectAllBtn();
                                    }};

                                    checkboxes.forEach(cb => {{
                                        cb.onchange = updateSelectAllBtn;
                                    }});

                                    updateSelectAllBtn();

                                    document.getElementById('owui-submit').onclick = () => {{
                                        const selected = [];
                                        checkboxes.forEach((cb, i) => {{
                                            if (cb.checked) selected.push(i);
                                        }});
                                        overlay.remove();
                                        document.removeEventListener('keydown', escHandler);
                                        resolve(selected);
                                    }};

                                    document.getElementById('owui-cancel').onclick = () => {{
                                        overlay.remove();
                                        document.removeEventListener('keydown', escHandler);
                                        resolve(null);
                                    }};

                                    const escHandler = (e) => {{
                                        if (e.key === 'Escape') {{
                                            overlay.remove();
                                            document.removeEventListener('keydown', escHandler);
                                            resolve(null);
                                        }}
                                    }};
                                    document.addEventListener('keydown', escHandler);

                                    overlay.addEventListener('click', (e) => {{
                                        if (e.target === overlay) {{
                                            overlay.remove();
                                            document.removeEventListener('keydown', escHandler);
                                            resolve(null);
                                        }}
                                    }});
                                }});
                            """
                        }
                    }
                )

                # Handle the response from the checkbox dialog
                if url_response is None:
                    await __event_emitter__(
                        {"type": "status", "data": {"description": "", "done": True}}
                    )
                    await __event_emitter__(
                        {
                            "type": "notification",
                            "data": {"type": "info", "content": "Action cancelled"},
                        }
                    )
                    return None

                selected_indices = set()
                if isinstance(url_response, list):
                    for idx in url_response:
                        try:
                            idx = int(idx)
                            if 0 <= idx < len(urls):
                                selected_indices.add(idx)
                        except (ValueError, TypeError):
                            pass

                if not selected_indices:
                    await __event_emitter__(
                        {"type": "status", "data": {"description": "", "done": True}}
                    )
                    await __event_emitter__(
                        {
                            "type": "notification",
                            "data": {
                                "type": "warning",
                                "content": "No valid URLs selected",
                            },
                        }
                    )
                    return None

                # Filter URLs to selected ones
                urls = [urls[i] for i in sorted(selected_indices)]

                # ────────────────────────────────────────────────
                # Step 2: Knowledge Base Selection Dialog (CHECKBOX + CREATE NEW)
                # Replaces old text-input with a radio-select modal
                # that also allows creating a new knowledge base inline.
                # ────────────────────────────────────────────────
                kb_names_json = _json.dumps(
                    [{"id": kb.id, "name": kb.name} for kb in knowledge_bases]
                )

                kb_response = await __event_call__(
                    {
                        "type": "execute",
                        "data": {
                            "code": f"""
                                return new Promise((resolve) => {{
                                    const kbs = {kb_names_json};
                                    const urlCount = {len(urls)};
                                    const overlay = document.createElement('div');
                                    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.5);display:flex;align-items:center;justify-content:center;z-index:9999;font-family:system-ui,-apple-system,sans-serif';

                                    let existingHtml = '';
                                    if (kbs.length === 0) {{
                                        existingHtml = '<div style="padding:16px;text-align:center;color:#888;font-size:13px">No existing knowledge bases found.</div>';
                                    }} else {{
                                        kbs.forEach((kb, i) => {{
                                            existingHtml += `
                                                <label style="display:flex;align-items:center;padding:10px 12px;margin:2px 0;border-radius:8px;cursor:pointer;transition:background 0.15s"
                                                       onmouseover="this.style.background='#f0f0f0'" 
                                                       onmouseout="this.style.background='transparent'"
                                                       onclick="document.getElementById('owui-create-new-name').value='';document.getElementById('owui-create-new-name').style.borderColor='#d0d0d0'">
                                                    <input type="radio" name="owui-kb-select" value="${{i}}" class="owui-kb-radio"
                                                           style="margin-right:10px;min-width:16px;width:16px;height:16px;cursor:pointer"/>
                                                    <div>
                                                        <div style="font-weight:500;font-size:13px;color:#1a1a1a">${{kb.name}}</div>
                                                    </div>
                                                </label>
                                            `;
                                        }});
                                    }}

                                    overlay.innerHTML = `
                                        <div style="background:#fff;border-radius:12px;box-shadow:0 20px 60px rgba(0,0,0,0.3);max-width:550px;width:90vw;max-height:80vh;display:flex;flex-direction:column">
                                            <div style="padding:16px 20px;border-bottom:1px solid #e5e5e5">
                                                <h3 style="margin:0;font-size:16px;font-weight:600">Select Knowledge Base</h3>
                                                <span style="font-size:13px;color:#888">Adding ${{urlCount}} source(s)</span>
                                            </div>
                                            <div style="overflow-y:auto;padding:4px 12px;flex:1;min-height:0">
                                                <div style="padding:8px 4px 4px;font-size:12px;font-weight:600;color:#888;text-transform:uppercase;letter-spacing:0.5px">Existing Collections</div>
                                                ${{existingHtml}}
                                                <div style="padding:12px 4px 4px;margin-top:8px;font-size:12px;font-weight:600;color:#888;text-transform:uppercase;letter-spacing:0.5px;border-top:1px solid #e5e5e5">Create New Collection</div>
                                                <label style="display:flex;align-items:center;padding:10px 12px;margin:2px 0;border-radius:8px;cursor:pointer;transition:background 0.15s"
                                                       onmouseover="this.style.background='#f0f0f0'" 
                                                       onmouseout="this.style.background='transparent'"
                                                       onclick="document.getElementById('owui-create-new-name').focus()">
                                                    <input type="radio" name="owui-kb-select" value="new" class="owui-kb-radio"
                                                           style="margin-right:10px;min-width:16px;width:16px;height:16px;cursor:pointer"/>
                                                    <div style="flex:1">
                                                        <input id="owui-create-new-name" type="text" placeholder="Enter new collection name..."
                                                               style="width:100%;padding:8px 10px;border:1px solid #d0d0d0;border-radius:6px;font-size:13px;outline:none;box-sizing:border-box;transition:border-color 0.15s"
                                                               onfocus="this.style.borderColor='#333';this.closest('label').querySelector('input[type=radio]').checked=true"
                                                               oninput="this.closest('label').querySelector('input[type=radio]').checked=true"/>
                                                    </div>
                                                </label>
                                            </div>
                                            <div style="padding:12px 20px;border-top:1px solid #e5e5e5;display:flex;gap:8px;justify-content:flex-end">
                                                <button id="owui-kb-cancel" style="padding:8px 20px;border:1px solid #d0d0d0;border-radius:8px;background:#fff;cursor:pointer;font-size:13px;font-weight:500;color:#555;transition:all 0.15s"
                                                        onmouseover="this.style.background='#f5f5f5'" 
                                                        onmouseout="this.style.background='#fff'">
                                                    Cancel
                                                </button>
                                                <button id="owui-kb-submit" style="padding:8px 24px;border:none;border-radius:8px;background:#1a1a1a;cursor:pointer;font-size:13px;font-weight:600;color:#fff;transition:all 0.15s"
                                                        onmouseover="this.style.background='#333'" 
                                                        onmouseout="this.style.background='#1a1a1a'">
                                                    Continue
                                                </button>
                                            </div>
                                        </div>
                                    `;

                                    document.body.appendChild(overlay);

                                    // Pre-select first existing KB if any, otherwise "create new"
                                    const radios = overlay.querySelectorAll('.owui-kb-radio');
                                    if (kbs.length > 0) {{
                                        radios[0].checked = true;
                                    }} else {{
                                        const newRadio = overlay.querySelector('input[value="new"]');
                                        if (newRadio) newRadio.checked = true;
                                    }}

                                    const createNewInput = document.getElementById('owui-create-new-name');

                                    document.getElementById('owui-kb-submit').onclick = () => {{
                                        const selected = overlay.querySelector('input[name="owui-kb-select"]:checked');
                                        if (!selected) {{
                                            alert('Please select a knowledge base or enter a new collection name.');
                                            return;
                                        }}
                                        if (selected.value === 'new') {{
                                            const name = createNewInput.value.trim();
                                            if (!name) {{
                                                createNewInput.style.borderColor = '#e00';
                                                createNewInput.focus();
                                                return;
                                            }}
                                            overlay.remove();
                                            document.removeEventListener('keydown', escHandler);
                                            resolve({{action: 'new', name: name}});
                                        }} else {{
                                            overlay.remove();
                                            document.removeEventListener('keydown', escHandler);
                                            resolve({{action: 'existing', index: parseInt(selected.value)}});
                                        }}
                                    }};

                                    document.getElementById('owui-kb-cancel').onclick = () => {{
                                        overlay.remove();
                                        document.removeEventListener('keydown', escHandler);
                                        resolve(null);
                                    }};

                                    const escHandler = (e) => {{
                                        if (e.key === 'Escape') {{
                                            overlay.remove();
                                            document.removeEventListener('keydown', escHandler);
                                            resolve(null);
                                        }}
                                    }};
                                    document.addEventListener('keydown', escHandler);

                                    overlay.addEventListener('click', (e) => {{
                                        if (e.target === overlay) {{
                                            overlay.remove();
                                            document.removeEventListener('keydown', escHandler);
                                            resolve(null);
                                        }}
                                    }});

                                    // Allow Enter key in the create-new input to submit
                                    createNewInput.addEventListener('keydown', (e) => {{
                                        if (e.key === 'Enter') {{
                                            e.preventDefault();
                                            document.getElementById('owui-kb-submit').click();
                                        }}
                                    }});
                                }});
                            """
                        }
                    }
                )

                # Handle the response from the KB selection dialog
                if kb_response is None:
                    await __event_emitter__(
                        {"type": "status", "data": {"description": "", "done": True}}
                    )
                    await __event_emitter__(
                        {
                            "type": "notification",
                            "data": {"type": "info", "content": "Action cancelled"},
                        }
                    )
                    return None

                if isinstance(kb_response, dict) and kb_response.get("action") == "existing":
                    idx = kb_response.get("index")
                    if isinstance(idx, int) and 0 <= idx < len(knowledge_bases):
                        selected_kb = knowledge_bases[idx]
                elif isinstance(kb_response, dict) and kb_response.get("action") == "new":
                    new_name = kb_response.get("name", "").strip()
                    if new_name:
                        # Create the new knowledge base
                        from open_webui.models.knowledge import KnowledgeForm

                        new_kb = await Knowledges.insert_new_knowledge(
                            user_id=__user__["id"],
                            form_data=KnowledgeForm(
                                name=new_name,
                                description=new_name,
                            ),
                        )
                        if new_kb:
                            selected_kb = new_kb
                            await __event_emitter__(
                                {
                                    "type": "notification",
                                    "data": {
                                        "type": "success",
                                        "content": f"Created new knowledge base: '{new_name}'",
                                    },
                                }
                            )
                        else:
                            await __event_emitter__(
                                {
                                    "type": "notification",
                                    "data": {
                                        "type": "error",
                                        "content": f"Failed to create knowledge base '{new_name}'.",
                                    },
                                }
                            )
                            return None
                    else:
                        await __event_emitter__(
                            {"type": "status", "data": {"description": "", "done": True}}
                        )
                        await __event_emitter__(
                            {
                                "type": "notification",
                                "data": {
                                    "type": "warning",
                                    "content": "No knowledge base name provided",
                                },
                            }
                        )
                        return None
                else:
                    await __event_emitter__(
                        {"type": "status", "data": {"description": "", "done": True}}
                    )
                    await __event_emitter__(
                        {
                            "type": "notification",
                            "data": {
                                "type": "error",
                                "content": "Invalid knowledge base selection.",
                            },
                        }
                    )
                    return None

            await __event_emitter__(
                {
                    "type": "status",
                    "data": {
                        "description": f"Adding {len(urls)} source(s) to '{selected_kb.name}'..."
                    },
                }
            )

            success_count = 0
            error_count = 0
            skipped_count = 0

            from open_webui.routers.retrieval import get_content_from_url
            from open_webui.models.files import Files, FileForm

            # Check for duplicates if enabled
            existing_sources = set()
            if self.valves.enable_duplicate_check:
                try:
                    # FIX: Handle 0.9.0 model attribute changes while keeping fallback for older versions
                    if hasattr(Knowledges, "get_file_metadatas_by_id"):
                        kb_files = await Knowledges.get_file_metadatas_by_id(
                            selected_kb.id
                        )
                        for kf in kb_files:
                            meta = (
                                kf.get("meta", {})
                                if isinstance(kf, dict)
                                else (kf.meta if hasattr(kf, "meta") else {})
                            )
                            if meta and meta.get("source"):
                                existing_sources.add(meta.get("source"))
                    elif hasattr(Knowledges, "get_knowledge_files_by_id"):
                        kb_files = await Knowledges.get_knowledge_files_by_id(
                            selected_kb.id
                        )
                        for kf in kb_files:
                            file = await Files.get_file_by_id(
                                kf.file_id
                                if hasattr(kf, "file_id")
                                else kf.get("file_id")
                            )
                            if file and file.meta and file.meta.get("source"):
                                existing_sources.add(file.meta.get("source"))
                except Exception as e:
                    print(f"[Add to Knowledge] Could not check duplicates: {e}")

            for idx, url_info in enumerate(urls):
                url = url_info["url"]

                if url in existing_sources:
                    print(f"[Add to Knowledge] Skipping duplicate: {url}")
                    skipped_count += 1
                    continue

                try:
                    await __event_emitter__(
                        {
                            "type": "status",
                            "data": {
                                "description": f"Processing ({idx+1}/{len(urls)}): {url[:40]}..."
                            },
                        }
                    )

                    # FIX: Safely execute the Langchain Playwright loader in an isolated thread to prevent asyncio crash
                    if inspect.iscoroutinefunction(get_content_from_url):
                        try:
                            content, docs = await get_content_from_url(__request__, url)
                        except Exception as inner_e:
                            if "Playwright" in str(inner_e) or "asyncio" in str(
                                inner_e
                            ):

                                def _sync_wrapper():
                                    import asyncio

                                    loop = asyncio.new_event_loop()
                                    asyncio.set_event_loop(loop)
                                    return loop.run_until_complete(
                                        get_content_from_url(__request__, url)
                                    )

                                content, docs = await asyncio.to_thread(_sync_wrapper)
                            else:
                                raise inner_e
                    else:
                        content, docs = await asyncio.to_thread(
                            get_content_from_url, __request__, url
                        )

                    if not content:
                        print(f"[Add to Knowledge] No content fetched for {url}")
                        error_count += 1
                        continue

                    # Create sanitized filename
                    sanitized_name = re.sub(
                        r"[^\w\-.]",
                        "_",
                        url.replace("http://", "")
                        .replace("https://", "")
                        .replace("www.", ""),
                    )[:100]

                    if effective_prefix:
                        sanitized_name = f"{effective_prefix}{sanitized_name}"

                    file_form = FileForm(
                        id=str(uuid.uuid4()),
                        filename=f"{sanitized_name}.txt",
                        path="",
                        meta={
                            "name": sanitized_name,
                            "content_type": "text/plain",
                            "source": url,
                        },
                        data={"content": content},
                    )

                    file = await Files.insert_new_file(
                        user_id=__user__["id"], form_data=file_form
                    )

                    if file:
                        result = await Knowledges.add_file_to_knowledge_by_id(
                            knowledge_id=selected_kb.id,
                            file_id=file.id,
                            user_id=__user__["id"],
                        )
                        if result:
                            success_count += 1
                            print(f"[Add to Knowledge] Added: {url}")
                        else:
                            error_count += 1
                    else:
                        error_count += 1

                except Exception as e:
                    print(f"[Add to Knowledge] Error processing {url}: {e}")
                    error_count += 1

            await __event_emitter__(
                {"type": "status", "data": {"description": "", "done": True}}
            )

            if success_count > 0:
                result_msg = f"Added {success_count} source(s) to '{selected_kb.name}'"
                if skipped_count > 0:
                    result_msg += f" ({skipped_count} duplicates skipped)"
                if error_count > 0:
                    result_msg += f" ({error_count} failed)"
                await __event_emitter__(
                    {
                        "type": "notification",
                        "data": {"type": "success", "content": result_msg},
                    }
                )
            elif skipped_count > 0 and error_count == 0:
                await __event_emitter__(
                    {
                        "type": "notification",
                        "data": {
                            "type": "info",
                            "content": f"All {skipped_count} source(s) already exist in '{selected_kb.name}'",
                        },
                    }
                )
            else:
                await __event_emitter__(
                    {
                        "type": "notification",
                        "data": {
                            "type": "error",
                            "content": "Failed to add sources. Check server logs for details.",
                        },
                    }
                )

            return None

        except Exception as e:
            print(f"[Add to Knowledge] Error: {e}")
            import traceback

            traceback.print_exc()

            await __event_emitter__(
                {"type": "status", "data": {"description": "", "done": True}}
            )
            await __event_emitter__(
                {
                    "type": "notification",
                    "data": {"type": "error", "content": f"Error: {str(e)}"},
                }
            )
            return None
